from flask import Flask, request, jsonify, g
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CONTENT_TYPE_LATEST, CollectorRegistry, multiprocess
import time
import random
import os

app = Flask(__name__)

REQUEST_COUNT = Counter(
    "flask_http_requests_total",
    "Total HTTP requests",
    ["method", "endpoint", "http_status"]
)

REQUEST_IN_PROGRESS = Gauge(
    "flask_http_requests_in_progress",
    "Number of HTTP requests in progress",
    ["method", "endpoint"]
)

REQUEST_LATENCY = Histogram(
    "flask_http_request_duration_seconds",
    "HTTP request latency in seconds",
    ["method", "endpoint"],
    buckets=(0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0)
)

ORDERS_CREATED = Counter(
    "business_orders_created_total",
    "Total number of orders created",
    ["status"]
)

ACTIVE_USERS = Gauge(
    "business_active_users",
    "Current number of active users"
)

ORDER_VALUE = Histogram(
    "business_order_value",
    "Distribution of order values",
    buckets=(10, 25, 50, 100, 250, 500, 1000, 2500, 5000)
)

INVENTORY_LEVEL = Gauge(
    "business_inventory_level",
    "Inventory level by product",
    ["product"]
)

PAYMENT_PROCESSING_TIME = Histogram(
    "business_payment_processing_seconds",
    "Payment processing time in seconds",
    ["provider"],
    buckets=(0.01, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0)
)

TASK_QUEUE_DEPTH = Gauge(
    "business_task_queue_depth",
    "Current depth of background task queue",
    ["queue_name"]
)

FAILED_PAYMENTS = Counter(
    "business_failed_payments_total",
    "Total failed payments",
    ["provider", "reason"]
)

for product in ("widget", "gadget", "premium_widget"):
    INVENTORY_LEVEL.labels(product=product).set(random.randint(50, 500))

ACTIVE_USERS.set(random.randint(5, 100))
TASK_QUEUE_DEPTH.labels(queue_name="default").set(random.randint(0, 20))
TASK_QUEUE_DEPTH.labels(queue_name="priority").set(random.randint(0, 10))


@app.before_request
def before_request():
    if request.path == "/metrics":
        return
    g.start_time = time.perf_counter()
    g.metric_endpoint = request.endpoint or request.path
    REQUEST_IN_PROGRESS.labels(method=request.method, endpoint=g.metric_endpoint).inc()


@app.after_request
def after_request(response):
    if request.path == "/metrics":
        return response
    endpoint = getattr(g, "metric_endpoint", request.endpoint or request.path)
    duration = time.perf_counter() - getattr(g, "start_time", time.perf_counter())
    REQUEST_LATENCY.labels(method=request.method, endpoint=endpoint).observe(duration)
    REQUEST_COUNT.labels(
        method=request.method,
        endpoint=endpoint,
        http_status=str(response.status_code)
    ).inc()
    REQUEST_IN_PROGRESS.labels(method=request.method, endpoint=endpoint).dec()
    return response


@app.teardown_request
def teardown_request(exception):
    if request.path == "/metrics":
        return
    if exception is not None:
        endpoint = getattr(g, "metric_endpoint", request.endpoint or request.path)
        try:
            REQUEST_COUNT.labels(
                method=request.method,
                endpoint=endpoint,
                http_status="500"
            ).inc()
            REQUEST_IN_PROGRESS.labels(method=request.method, endpoint=endpoint).dec()
        except Exception:
            pass


@app.route("/")
def index():
    return jsonify({
        "service": "flask-monitoring-app",
        "status": "ok",
        "endpoints": ["/", "/health", "/orders", "/users/active", "/inventory", "/simulate-payment", "/metrics"]
    })


@app.route("/health")
def health():
    return jsonify({"status": "healthy"}), 200


@app.route("/orders", methods=["POST"])
def create_order():
    payload = request.get_json(silent=True) or {}
    order_value = float(payload.get("value", random.uniform(20, 1500)))
    provider = payload.get("provider", random.choice(["stripe", "paypal", "adyen"]))

    ORDER_VALUE.observe(order_value)
    PAYMENT_PROCESSING_TIME.labels(provider=provider).observe(random.uniform(0.02, 1.2))

    if random.random() < 0.15:
        FAILED_PAYMENTS.labels(provider=provider, reason="processor_error").inc()
        ORDERS_CREATED.labels(status="failed").inc()
        return jsonify({"status": "failed", "provider": provider}), 402

    ORDERS_CREATED.labels(status="success").inc()
    ACTIVE_USERS.inc()
    TASK_QUEUE_DEPTH.labels(queue_name="default").inc()

    return jsonify({
        "status": "created",
        "order_value": order_value,
        "provider": provider
    }), 201


@app.route("/users/active", methods=["GET", "POST"])
def users_active():
    if request.method == "POST":
        payload = request.get_json(silent=True) or {}
        value = int(payload.get("count", random.randint(1, 200)))
        ACTIVE_USERS.set(value)
    return jsonify({"active_users": ACTIVE_USERS._value.get()})


@app.route("/inventory", methods=["GET", "POST"])
def inventory():
    if request.method == "POST":
        payload = request.get_json(silent=True) or {}
        product = payload.get("product", "widget")
        level = int(payload.get("level", random.randint(0, 500)))
        INVENTORY_LEVEL.labels(product=product).set(level)
        return jsonify({"product": product, "level": level})
    products = {
        "widget": INVENTORY_LEVEL.labels(product="widget")._value.get(),
        "gadget": INVENTORY_LEVEL.labels(product="gadget")._value.get(),
        "premium_widget": INVENTORY_LEVEL.labels(product="premium_widget")._value.get(),
    }
    return jsonify(products)


@app.route("/simulate-payment", methods=["POST"])
def simulate_payment():
    payload = request.get_json(silent=True) or {}
    provider = payload.get("provider", random.choice(["stripe", "paypal", "adyen"]))
    duration = random.uniform(0.01, 3.0)
    PAYMENT_PROCESSING_TIME.labels(provider=provider).observe(duration)

    if random.random() < 0.2:
        FAILED_PAYMENTS.labels(provider=provider, reason="timeout").inc()
        return jsonify({"status": "failed", "provider": provider, "duration_seconds": duration}), 500

    return jsonify({"status": "success", "provider": provider, "duration_seconds": duration})


@app.route("/metrics")
def metrics():
    multiproc_dir = os.getenv("PROMETHEUS_MULTIPROC_DIR")
    if multiproc_dir:
        registry = CollectorRegistry()
        multiprocess.MultiProcessCollector(registry)
        data = generate_latest(registry)
    else:
        data = generate_latest()
    return app.response_class(data, mimetype=CONTENT_TYPE_LATEST)


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))